export const TOPIC_LIST = Object.values(TOPIC_BUNDLES).map((b) => ({
  slug: b.ward.slug,
  title: b.ward.title,
  system: b.ward.system,
  subSystem: b.ward.subSystem || '',
  acuity: b.ward.acuity,
  highYield: b.ward.acuity === 'EMERGENCY' || b.ward.acuity === 'URGENT',
}));

// Group topics by system for the sidebar display
export const TOPICS_BY_SYSTEM = TOPIC_LIST.reduce<Record<string, typeof TOPIC_LIST>>((acc, t) => {
  if (!acc[t.system]) acc[t.system] = [];
  acc[t.system].push(t);
  return acc;
}, {});

// Sort systems alphabetically for predictable display
export const SYSTEMS_ORDERED = Object.keys(TOPICS_BY_SYSTEM).sort();
